For verilator, anyone have experience using dump() with non-integer timestamp ?

The reason for non-integer timestamp is due to pico-second time precision (10417ps or 10.417ns) required in the following cpp testbench:

 #define    TRACE_POSEDGE    if (tfp != NULL) tfp->dump(time_ps/1000)                                                                                                                                                      
 #define    TRACE_NEGEDGE    if (tfp != NULL) tfp->dump(time_ps/1000)



```<code class="cpp">
#include <verilated.h>          // Defines common routines
#include "VTx_top.h"

#include "verilated_vcd_c.h"

#include <iostream>
#include <string>
#include <cstdlib>
#include <cstdio>

#define Tx_IDLE		0
#define	TRACE_POSEDGE	if (tfp != NULL) tfp->dump(time_ps/1000)
#define	TRACE_NEGEDGE	if (tfp != NULL) tfp->dump(time_ps/1000)
#define	TRACE_CLOSE	if (tfp != NULL) tfp->close()

VTx_top *uut;                     // Instantiation of module
unsigned int time_ps = 0;       	// Current simulation time in picoseconds

double sc_time_stamp () {       // Called by $time in Verilog
     return time_ps/1000;        // divide by 1000ps/ns and converts to double, to match
     // what SystemC does
}

bool check_output(unsigned index) {  		// check if the Tx UART serializer works correctly

     unsigned int bit_value = (!!(uut->i_data & (1<<index)) == true) ? 1 : 0;  // serialized bit
     cout << "bit_value = " << bit_value << endl;

     // decoding starts


     // decoding ends

     //assert( == uut->i_data);  // we decode the Tx serialized output (uut-> serial_out) to see if it matches with input data

     //if (index==10) return true;
     //else 
return false;
}

void cout_debug_msg(void) {
     cout << " clk = " << (int)uut->clk ;
     cout << " baud_out = " << (int)uut->Tx_top__DOT__bg__DOT__ck_stb ;   
     //cout << " uut->serial_out = " << (int)uut->Tx_top__DOT__serial_out << endl;
     cout << "-------------------------------------------------------" << endl;
}


int main(int argc, char** argv)
{ 
     // turn on trace or not?
     bool vcdTrace = true;
     VerilatedVcdC* tfp = NULL;

     Verilated::commandArgs(argc, argv);   // Remember args
     uut = new VTx_top;   // Create instance

     if (vcdTrace)
     {
         Verilated::traceEverOn(true);

         tfp = new VerilatedVcdC;
         uut->trace(tfp, 99);

         std::string vcdname = argv[0];
         vcdname += ".vcd";
         std::cout << vcdname << std::endl;
         tfp->open(vcdname.c_str());
     }

     uut->start = 0;
     //uut->reset = 0;
     uut->i_data = 0x9A;   // 8-bits binary : 1001_1010
     uut->clk = 0;
     uut->eval();

     while (!Verilated::gotFinish())   // 2100577 ns is the end of transmission for 0x9A
     {
	time_ps = time_ps + 10417; 	// 10417ps or 10.417ns is half of clock period for 48MHz

	uut->start = ((time_ps < 104167*3*1000) || (time_ps > 104167*4*1000)) ? 0 : 1;  // start signal is only HIGH for 1 baud_out cycle whhich is 104167ns or (104167*1000)ps

	uut->clk = 1; 
	uut->eval(); 
	TRACE_POSEDGE; 

	time_ps = time_ps + 10417; 

	uut->clk = 0; 
	uut->eval(); 
	TRACE_NEGEDGE;

	// UART Tx is transmitting 11 characters (1 start bit, 8 data bits, 1 parity bit, 1 stop bit), so busy

	if ((time_ps % 104167) == 0) {     // check Tx output at every rising edge of baud_out (9600bps)
	    cout_debug_msg();

	    // start checking UART Tx output when serial_out line drops from '1' to '0'
	    //if ()
	    	bool result_is_correct = check_output((time_ps-11*104167)/104167);   
	    //cout << "result_is_correct = " << result_is_correct << endl;
	    //if ((uut->Tx_top__DOT__tx__DOT__state == Tx_IDLE) && (uut->start == 0) && (result_is_correct == true)) break;   // finish transmitting 11 characters correctly
	}
     }

     uut->final();               // Done simulating

     TRACE_CLOSE;

     delete uut;

     return 0;
}
